  ('elementary-d0d1b9a2-moex-00740', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-111-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '雲林縣斗六市之財務審計，由下列何機關辦理？', '["審計部", "臺灣省審計處", "雲林縣審計室", "斗六市審計室"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "de3a8c883d8e", "answer_pdf_sha1": "f69b8d65e73e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00741', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00742', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00743', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '近年來雙薪家庭比例上升，由於父母忙於工作，因此托兒所、安親班等機構成為安置孩童的重要處所。 根據統計，臺灣目前有政府立案的各種安親班、補習班、才藝班數量遠遠超過全臺超商數量。此現象說 明隨著社會變遷，家庭的何種功能正在轉變？', '["生育功能", "經濟功能", "社會化功能", "傳遞社會地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00744', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '所謂「友善職場」，就是無歧視、重平等的職場。在職場中，勞工與雇主彼此尊重、合作，共同打造一 個性別平權的工作環境。下列何種作法，最有助於促進「友善職場」？', '["開放同志勞工因伴侶生病時可請家庭照顧假", "營造玻璃天花板環境以便落實性別實質平等", "健全性別職業隔離制度以保障女性就業機會", "降低女性勞動參與率以避免蠟燭兩頭燒現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
